import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists(): return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing: existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]: existing[ch][v] = html

CHRIST = {
  "1": {
    "1": "<p>A revelation of God: YHWH speaks to Moses from within the tent of meeting — the completed tabernacle has become the place of divine speech. The God who commands sacrifice is the God who will himself provide the ultimate sacrifice; the instructions now given from within the sanctuary point forward to the one who will enter the greater sanctuary not made with hands (Heb 9:11).</p>",
    "2": "<p>A shadow: 'Speak to the people of Israel and say to them, When any one of you brings an offering to YHWH, you shall bring your offering of livestock from the herd or from the flock.' The entire Levitical offering system is a comprehensive shadow-structure. Hebrews calls the law 'a shadow of the good things to come' (Heb 10:1); what is outlined in exhaustive detail in Leviticus 1–7 is the shadow of the one sacrifice of Christ.</p>",
    "3": "<p>A direct type: 'If his offering is a burnt offering from the herd, he shall offer a male without blemish [<em>tamim</em>].' The requirement of <em>tamim</em> (complete, without defect) in the sacrificial animal is the OT's most persistent type of Christ's sinlessness. 1 Peter 1:18–19 makes the connection explicit: 'You were ransomed... with the precious blood of Christ, like that of a lamb without blemish [<em>amōmos</em>] or spot.' Hebrews 9:14 similarly: 'Christ... offered himself without blemish to God.' Every animal rejected for defect announced that only a perfect substitute could make atonement.</p>",
    "4": "<p>A direct type: 'He shall lay his hand on the head of the burnt offering, and it shall be accepted for him to make atonement for him.' The hand-laying rite (<em>semichah</em>) is the sacrificial system's most explicit act of identification and substitution — the offerer transfers his own identity onto the animal, which then stands in his place. The NT applies this substitutionary logic to Christ: 'God made him who had no sin to be sin for us' (2 Cor 5:21); 'He himself bore our sins in his body on the tree' (1 Pet 2:24). The hand-press of <em>semichah</em> becomes the imputation of the believer's sin to Christ.</p>",
    "5": "<p>A direct type: 'Then he shall kill the bull before YHWH, and Aaron's sons the priests shall bring the blood and throw the blood against the sides of the altar.' Blood thrown against the altar is the essential sacrificial act — Hebrews 9:22: 'Without the shedding of blood there is no forgiveness of sins.' The requirement that blood be actively presented (not merely spilled) reflects the deliberate, purposeful nature of atonement — and points to Christ's deliberate, voluntary death (John 10:17–18: 'I lay it down of my own accord').</p>",
    "6": "<p>A shadow: 'And he shall flay the burnt offering and cut it into pieces.' The complete dismemberment and examination of the offering ensures that nothing is concealed or hidden — the sacrifice must be transparent, without hidden defects. Christ submitted to complete exposure: interrogated, stripped, examined publicly — 'this is the judgment, that the light has come into the world' (John 3:19).</p>",
    "7": "<p>A shadow: 'The sons of Aaron the priest shall put fire on the altar and arrange wood on the fire.' The altar fire was kept continuously burning (Lev 6:12–13, 'the fire on the altar shall be kept burning; it shall not go out'). This perpetual fire is the image of God's consuming holiness — the fire into which Christ entered: 'our God is a consuming fire' (Heb 12:29). The cross was not an accident of history but a divine altar-fire prepared before creation (Rev 13:8).</p>",
    "8": "<p>A shadow: 'And Aaron's sons the priests shall arrange the pieces, the head, and the fat, on the wood that is on the fire on the altar.' Every part of the sacrifice is carefully arranged — nothing is left off the altar. Christ's offering was total: body, soul, and spirit fully given. 'I give my flesh for the life of the world' (John 6:51) — and more than flesh: 'He offered himself without blemish to God' (Heb 9:14).</p>",
    "9": "<p>A direct type: 'Its entrails and its legs he shall wash with water. And the priest shall burn all of it on the altar, as a burnt offering, a food offering with a pleasing aroma [<em>reah nichoach</em>] to YHWH.' The <em>olah</em> (burnt offering) is entirely consumed — the word means 'ascending'; every part rises to God as smoke. This total consumption is the type of Christ's total self-giving: 'He loved me and gave himself for me' (Gal 2:20). Paul describes Christ's sacrifice using the <em>reah nichoach</em> formula exactly: 'a fragrant offering and sacrifice to God' (Eph 5:2).</p>",
    "10": "<p>A direct type: 'If his gift for a burnt offering is from the flock, from the sheep or goats, he shall bring a male without blemish [<em>tamim</em>].' The requirement of perfection is repeated for each animal category. The repetition is pedagogical — Israel is trained through constant repetition to understand that no imperfect substitute can stand. Christ's sinlessness is not incidental but structurally required by the entire sacrificial system: 'a lamb without blemish or spot, foreknown before the foundation of the world' (1 Pet 1:19–20).</p>",
    "11": "<p>A shadow: 'And he shall kill it on the north side of the altar before YHWH.' The north side of the altar became the traditional slaughter site — the geography of sacrifice is defined. At Golgotha, the site of Christ's death was outside the north gate of Jerusalem, outside the camp (Heb 13:12) — matching the pattern that sin-offerings were burned outside the camp (Lev 4:12, 21).</p>",
    "12": "<p>A shadow: 'And he shall cut it into pieces, with its head and its fat, and the priest shall arrange them on the wood that is on the fire on the altar.' The care taken in the arrangement of every piece emphasizes completeness — no part left off. Christ's atonement is complete: 'It is finished' (John 19:30) — the Greek <em>tetelestai</em> is an accounting term for 'paid in full.'</p>",
    "13": "<p>A direct type: 'But the entrails and the legs he shall wash with water. And the priest shall offer all of it and burn it on the altar; it is a burnt offering, a food offering with a pleasing aroma to YHWH.' The repeated <em>reah nichoach</em> formula (vv. 9, 13, 17) hammers the note of divine acceptance. The cross was not defeat but acceptance — the Father accepted the sacrifice: 'Therefore God has highly exalted him' (Phil 2:9). Paul explicitly applies the Levitical formula: Christ 'gave himself up for us, a fragrant offering and sacrifice to God' (Eph 5:2).</p>",
    "14": "<p>A direct type: 'If his offering to YHWH is a burnt offering of birds, he shall bring his offering of turtledoves or pigeons.' The bird offering was the poor man's provision — the same offering Mary brought at Jesus's presentation (Luke 2:24: 'a pair of turtledoves or two young pigeons'), identifying Christ with the poor. James 2:5: 'Has not God chosen those who are poor in the world to be rich in faith?' Christ entered the sacrificial system from the lowest economic level of offering, signaling that atonement is accessible regardless of wealth.</p>",
    "15": "<p>A shadow: 'And the priest shall bring it to the altar and wring off its head and burn it on the altar. Its blood shall be drained out on the side of the altar.' The bird offering involves the priest's direct action — he himself wrings off the head. Christ's sacrifice involved direct divine action: 'It was the will of YHWH to crush him' (Isa 53:10). The Spirit came upon Jesus as a dove at his baptism (Matt 3:16) — marking him as the dove-offering that the Father himself would offer.</p>",
    "16": "<p>A shadow: 'He shall remove its crop with its contents and cast it beside the altar on the east side, in the place for ashes.' The crop is removed — what the bird has ingested, what it has fed on from the earth. Christ, though taking on human flesh, was without sin — 'holy, innocent, unstained, separated from sinners' (Heb 7:26). The removal of the crop is a type of Christ's complete freedom from what corrupts.</p>",
    "17": "<p>A direct type: 'He shall tear it open by its wings, but shall not sever it completely. And the priest shall burn it on the altar, on the wood that is on the fire. It is a burnt offering, a food offering with a pleasing aroma to YHWH.' The third repetition of <em>reah nichoach</em> closes chapter 1. The threefold repetition — for cattle (v9), small cattle (v13), birds (v17) — spans all economic levels of offering. At every level, the same result: a pleasing aroma accepted by God. The richest and the poorest brought the same acceptance. Christ, offered once, was accepted for all (Heb 10:14: 'by a single offering he has perfected for all time those who are being sanctified').</p>"
  },
  "2": {
    "1": "<p>A direct type: 'When anyone brings a grain offering [<em>minchah</em>] as an offering to YHWH, his offering shall be of fine flour. He shall pour oil on it and put frankincense on it.' The grain offering's three elements are a three-way type: fine flour (<em>solet</em>) = Christ's sinless humanity — the finest grain, sifted without blemish; oil = the Holy Spirit — Jesus was anointed with the Spirit (Acts 10:38; Luke 4:18); frankincense = prayer and intercession — 'The prayers of the saints... golden bowls full of incense' (Rev 5:8). The grain offering is the type of the Incarnation.</p>",
    "2": "<p>A shadow: 'And he shall bring it to Aaron's sons the priests. And he shall take from it a handful of the fine flour and oil, with all of its frankincense, and the priest shall burn this as its memorial portion on the altar, a food offering with a pleasing aroma to YHWH.' The <em>azkarah</em> (memorial/reminder portion) represents the whole — a handful stands for the entire offering. Christ's one sacrifice represents and effects the whole of atonement: 'He has appeared once for all at the end of the ages to put away sin by the sacrifice of himself' (Heb 9:26).</p>",
    "3": "<p>A direct type: 'But the rest of the grain offering shall be for Aaron and his sons; it is a most holy part of YHWH's food offerings.' The priests eat the remainder of the grain offering — they are sustained by the sacrifice. Christ is both the offering and the bread: 'I am the bread of life' (John 6:35); 'the bread that I will give for the life of the world is my flesh' (John 6:51). The priests eating the grain offering type the believer's feeding on Christ in faith and in the Eucharist (1 Cor 10:16).</p>",
    "4": "<p>A direct type: 'When you bring a grain offering baked in the oven as an offering, it shall be unleavened loaves of fine flour mixed with oil, or unleavened wafers smeared with oil.' Unleavened (<em>matzot</em>) = without leaven = without sin. Paul interprets leaven as sin and malice (1 Cor 5:7–8): 'Cleanse out the old leaven... as you really are unleavened. For Christ, our Passover lamb, has been sacrificed.' The absence of leaven in the grain offering is the type of Christ's sinlessness — the fine flour of his humanity, tested and baked by suffering (Heb 2:10), contains no corruption.</p>",
    "5": "<p>A shadow: 'And if your offering is a grain offering cooked on a griddle, it shall be of fine flour unleavened, mixed with oil.' The multiple preparation forms (oven, griddle, pan) show that the sacrificial principle applies across varied forms — as does Christ's one sacrifice: applicable across all times, peoples, and circumstances.</p>",
    "6": "<p>A direct type: 'You shall break it in pieces and pour oil on it; it is a grain offering.' Breaking in pieces with oil poured over — a eucharistic image: 'He broke it and gave it to the disciples, saying, Take, eat; this is my body' (Matt 26:26). The grain offering of broken pieces with oil is the OT form of what Christ instituted at the Last Supper.</p>",
    "7": "<p>A shadow: 'And if your offering is a grain offering cooked in a pan, it shall be made of fine flour with oil.' The third preparation method; the consistent requirements — fine flour, oil, no leaven — remain across all forms. Christ's nature is constant across all expressions of his work: the same sinless humanity, the same Spirit-anointing, whether as teacher, healer, or sacrifice.</p>",
    "8": "<p>A shadow: 'And you shall bring the grain offering that is made of these things to YHWH, and when it is presented to the priest, he shall bring it to the altar.' The offering must be brought to the priest, who brings it to the altar. Christ is both the offerer who brings himself and the priest who presents the sacrifice — the author and perfecter of our faith who 'offered himself without blemish to God' (Heb 9:14).</p>",
    "9": "<p>A shadow: 'And the priest shall take from the grain offering its memorial portion and burn this on the altar, a food offering with a pleasing aroma to YHWH.' The <em>azkarah</em> burned on the altar is the portion that ascends — the part given wholly to God. In Christ's sacrifice, the offering is entirely God's: 'He offered himself without blemish to God' (Heb 9:14). The Father accepted it: 'a fragrant offering and sacrifice to God' (Eph 5:2).</p>",
    "10": "<p>A shadow: 'But the rest of the grain offering shall be for Aaron and his sons; it is a most holy part of YHWH's food offerings.' What is not burned belongs to the priests — holy food for holy service. The gospel makes believers a 'royal priesthood' (1 Pet 2:9) who feed on Christ. What Christ offers entirely to God, he then gives as food to his priests.</p>",
    "11": "<p>A direct type: 'No grain offering that you bring to YHWH shall be made with leaven, for you shall burn no leaven and no honey as a food offering to YHWH.' The absolute prohibition on leaven makes it the most explicit type in the grain offering: leaven = sin and corruption. 'Do you not know that a little leaven leavens the whole lump? Cleanse out the old leaven... for Christ, our Passover lamb, has been sacrificed' (1 Cor 5:6–7). The no-leaven rule announces that atonement requires a sinless sacrifice — only Christ qualifies.</p>",
    "12": "<p>A shadow: 'As an offering of firstfruits you may bring them to YHWH, but they shall not be offered on the altar for a pleasing aroma.' The graduated system: first-fruits may include leaven and honey but they cannot ascend as atoning sacrifice. Only what is without leaven can atone. This shows that even good things — the natural produce of the earth — cannot serve as an atoning sacrifice. Only the one without leaven can bear sin.</p>",
    "13": "<p>A direct type: 'You shall season all your grain offerings with salt. You shall not let the salt of the covenant with your God be lacking from your grain offering; with all your offerings you shall offer salt.' Salt = covenant permanence and incorruption (salt preserves). The 'covenant of salt' (<em>berit melach</em>) is the most permanent of covenants — it cannot be corrupted. Christ's sacrifice establishes 'the eternal covenant' (Heb 13:20) by his blood — the incorruptible salt-covenant that never expires.</p>",
    "14": "<p>A direct type: 'If you offer a grain offering of firstfruits to YHWH, you shall offer for the grain offering of your firstfruits fresh ears, roasted with fire, crushed new grain.' The first-fruits offering is a type of the resurrection. Paul: 'Christ has been raised from the dead, the firstfruits of those who have fallen asleep' (1 Cor 15:20). Jesus is the first-fruits grain — roasted and crushed (death and burial), but the first to rise from the ground in resurrection.</p>",
    "15": "<p>A shadow: 'And you shall put oil on it and lay frankincense on it; it is a grain offering.' Oil and frankincense on the first-fruits: the Spirit and prayer/intercession attend the first-fruits offering. At the resurrection, the Spirit who raised Jesus (Rom 8:11) is the same who anointed him. The risen Christ intercedes (Heb 7:25) — frankincense rising before God.</p>",
    "16": "<p>A shadow: 'And the priest shall burn the memorial portion, some of the crushed grain and some of the oil with all of its frankincense; it is a food offering to YHWH.' The first-fruits' <em>azkarah</em> burns as a pleasing aroma — the culminating promise of the grain offering chapter: even the first-fruits, roasted and crushed, are accepted by God. The resurrection is not a divine afterthought but an accepted offering: 'God... gave him glory, so that your faith and hope are in God' (1 Pet 1:21).</p>"
  },
  "3": {
    "1": "<p>A direct type: 'If his offering is a sacrifice of peace offering [<em>zebach shelamim</em>], if he offers an animal from the herd, male or female, he shall offer it without blemish [<em>tamim</em>] before YHWH.' The <em>shelamim</em> (peace offering, from <em>shalom</em>) uniquely features the offerer eating from the sacrifice in communion with God and the priests. Christ is our peace: 'He himself is our peace, who has made us both one and has broken down in his flesh the dividing wall of hostility' (Eph 2:14). The communion meal of the peace offering is the type of the Lord's Supper — restored fellowship between God and man at the table.</p>",
    "2": "<p>A direct type: 'And he shall lay his hand on the head of his offering and kill it at the entrance of the tent of meeting, and Aaron's sons the priests shall throw the blood against the sides of the altar.' Hand-laying (<em>semichah</em>) appears again — the peace offering also requires identification, not just gratitude. The worshiper approaches not on the basis of his own worthiness but through substitutionary identification. Christ is the one who makes sinners acceptable to draw near (Heb 10:22: 'let us draw near with a true heart').</p>",
    "3": "<p>A direct type: 'And from the sacrifice of the peace offering, as a food offering to YHWH, he shall offer the fat covering the entrails and all the fat that is on the entrails.' The fat portions (the richest, most energetic parts of the animal) are given entirely to YHWH — not eaten, not given to priests. The richest belongs to God alone. Christ gave what was most precious: 'Though he was in the form of God, he did not count equality with God a thing to be grasped, but emptied himself' (Phil 2:6–7) — the ultimate giving of the richest for God's purpose.</p>",
    "4": "<p>A shadow: 'And the two kidneys with the fat that is on them at the loins, and the long lobe of the liver that he shall remove with the kidneys.' The internal anatomy given to God — what is hidden, internal, private. Christ's self-giving was internal and total: 'not my will, but yours, be done' (Luke 22:42). The kidneys in Hebrew thought (<em>kelayot</em>) were the seat of the inner life; giving them to God types the complete inner surrender of Gethsemane.</p>",
    "5": "<p>A shadow: 'Then Aaron's sons shall burn it on the altar on top of the burnt offering, which is on the wood on the fire; it is a food offering with a pleasing aroma to YHWH.' The peace offering burns on top of the burnt offering — it presupposes the olah beneath it. Peace with God (shelamim) rests on the foundation of total consecration (olah). Christ first consecrated himself entirely (John 17:19: 'I sanctify myself') and then made peace through the blood of his cross (Col 1:20).</p>",
    "6": "<p>A direct type: 'If his offering for a peace offering to YHWH is an animal from the flock, male or female, he shall offer it without blemish.' The peace offering uniquely accepts male or female — in this offering, the gender distinction of the olah (male only) is removed. This anticipates Paul's declaration: 'There is neither male nor female, for you are all one in Christ Jesus' (Gal 3:28). The peace Christ makes is equally available to all.</p>",
    "7": "<p>A direct type: 'If he offers a lamb for his offering, then he shall offer it before YHWH, lay his hand on the head of his offering, and kill it in front of the tent of meeting.' The lamb peace offering sets up the central NT image: Christ as 'the Lamb of God, who takes away the sin of the world' (John 1:29). The hand-laying at the peace offering means the worshiper's need for peace — his estrangement from God — is transferred to the lamb.</p>",
    "8": "<p>A direct type: 'Aaron's sons shall throw its blood against the sides of the altar.' Blood-throwing at the altar marks the peace offering as still fundamentally an atonement rite — fellowship with God is possible only through blood-mediated reconciliation. Colossians 1:20: God was pleased 'through him to reconcile to himself all things, whether on earth or in heaven, making peace by the blood of his cross.'</p>",
    "9": "<p>A shadow: 'Then from the sacrifice of the peace offering he shall offer as a food offering to YHWH its fat; he shall remove the whole fat tail, cut off close to the backbone, and the fat that covers the entrails and all the fat that is on the entrails.' The fat tail (<em>ha-alyah</em>) — unique to broad-tailed sheep — is given entirely to YHWH. What is characteristically unique to the animal, its distinguishing feature, is offered to God. Christ offered what was uniquely his — his divine-human nature, the one thing no one else could give.</p>",
    "10": "<p>A shadow: 'And the two kidneys with the fat that is on them at the loins, and the long lobe of the liver that he shall remove with the kidneys.' Repeated from v4 for the sheep variety — the internal organs that represent the hidden life. Christ's offering was not merely external conduct but the hidden obedience of his inner life: 'he learned obedience through what he suffered' (Heb 5:8).</p>",
    "11": "<p>A direct type: 'And the priest shall burn it on the altar as a food offering to YHWH.' The peace offering is <em>lechem isheh</em> — 'food of the fire offering' or 'food offering.' God receives the sacrifice as nourishment — a figure of speech for acceptable worship. Christ calls himself the bread of life (John 6:35) and at the Eucharist, his body and blood are given as food: 'unless you eat the flesh of the Son of Man and drink his blood, you have no life in you' (John 6:53). The communion meal of the peace offering becomes the Lord's Supper.</p>",
    "12": "<p>A shadow: 'If his offering is a goat, then he shall offer it before YHWH.' The third animal option — goat. The broad inclusivity of the peace offering (cattle, sheep, goat) mirrors the universality of the peace Christ makes: 'he is the propitiation for our sins, and not for ours only but also for the sins of the whole world' (1 John 2:2).</p>",
    "13": "<p>A direct type: 'And he shall lay his hand on its head and kill it in front of the tent of meeting, and the sons of Aaron shall throw its blood against the sides of the altar.' The third repetition of hand-laying in chapter 3 (for cattle v2, sheep v7, goat v13). The triple repetition across all three animal types establishes identification/substitution as an absolute requirement — no peace offering without hand-laying, no peace with God without Christ bearing what we are.</p>",
    "14": "<p>A shadow: 'Then he shall offer from it, as his offering for a food offering to YHWH, the fat covering the entrails and all the fat that is on the entrails.' Fat portions again — the richest given to God. The goat's fat portions are identical to the cattle's and sheep's: the same principle governs all. The offering of the best to God is universal.</p>",
    "15": "<p>A shadow: 'And the two kidneys with the fat that is on them at the loins, and the long lobe of the liver that he shall remove with the kidneys.' The third occurrence of the kidney formula (vv4, 10, 15) — one for each animal type. The inner organs given to God type the complete inner surrender Christ made. Hebrews 10:7 applies Ps 40 to Christ: 'I have come to do your will, O God' — not outer compliance but the deepest inner obedience.</p>",
    "16": "<p>A direct type: 'And the priest shall burn them on the altar as a food offering with a pleasing aroma. All fat is YHWH's.' <em>Kol-chelev laYHWH</em> — 'all fat is YHWH's.' This is the absolute principle underlying the peace offering: the best, the richest, belongs to God alone. Christ's sacrifice was the offering of what was most precious to God — his own Son (Rom 8:32: 'He who did not spare his own Son but gave him up for us all'). The 'all fat is YHWH's' rule means nothing was withheld: 'he loved me and gave himself for me' (Gal 2:20).</p>",
    "17": "<p>A direct type: 'It shall be a statute forever throughout your generations, in all your dwelling places, that you eat neither fat nor blood.' The double prohibition — no fat, no blood — is the peace offering's lasting theological boundary. Blood cannot be consumed because blood = life, and life belongs to God; it must be given to God (v16's <em>kol-chelev laYHWH</em>). Christ's blood cannot simply be possessed or managed by humanity — it must be received as the gift of the one who owned it: 'This is my blood of the covenant, which is poured out for many for the forgiveness of sins' (Matt 26:28). The no-blood-consumption rule prevents Israel from thinking of sacrifice as magic they control; it must be received as grace.</p>"
  },
  "4": {
    "1": "<p>A shadow: YHWH spoke to Moses about the sin offering (<em>chatat</em>). The sin offering chapter introduces a new category: the offering for <em>shegagah</em> (unintentional sin, mistakes, errors). The Levitical system distinguishes sins done in error from those done 'with a high hand' (defiantly, Num 15:30–31). The <em>chatat</em> addresses the former. Christ's intercession from the cross covers both: 'Father, forgive them, for they know not what they do' (Luke 23:34); his atoning work covers the full range of human failure.</p>",
    "2": "<p>A direct type: 'Speak to the people of Israel, saying, If anyone sins unintentionally [<em>bishgagah</em>] in any of YHWH's commandments about things not to be done, and does any one of them...' The sin offering is specifically for unintentional violations — sins of ignorance, weakness, and error. Peter frames the crucifixion itself as an act done in ignorance: 'you acted in ignorance, as did also your rulers' (Acts 3:17). Christ's prayer from the cross applies the <em>chatat</em> logic directly: the unknowing transgressor is covered by the sacrificial provision.</p>",
    "3": "<p>A direct type: 'If it is the anointed priest who sins, thus bringing guilt on the people, then he shall offer for the sin that he has committed a bull from the herd without blemish to YHWH for a sin offering.' The anointed priest's sin offering is the most costly — a whole bull. The irony is profound: the one appointed to bring others near to God must first bring his own sin offering. Hebrews presses this contrast: 'For it was indeed fitting that we should have such a high priest, holy, innocent, unstained, separated from sinners... He has no need, like those high priests, to offer sacrifices daily, first for his own sins and then for those of the people' (Heb 7:26–27). The Levitical priest's self-atonement requirement is the very deficiency Christ removes.</p>",
    "4": "<p>A direct type: 'He shall bring the bull to the entrance of the tent of meeting before YHWH and lay his hand on the head of the bull and kill the bull before YHWH.' Hand-laying appears even in the priest's own sin offering — the priest identifies with the bull just as any layman would. The sacrificial system makes no exemption for the one performing it; everyone who approaches must come through identification with the substitute. Christ 'learned obedience through what he suffered' (Heb 5:8) — he approached through suffering, not exemption from it.</p>",
    "5": "<p>A direct type: 'And the anointed priest shall take some of the blood of the bull and bring it into the tent of meeting.' The sin offering's blood is brought <em>inside</em> the tent — unlike the burnt and peace offerings whose blood is thrown against the outer altar. The penetration of blood into the sanctuary is the key typological act. Hebrews 9:11–12: 'But when Christ appeared as a high priest of the good things that have come... he entered once for all into the holy places, not by means of the blood of goats and calves but by means of his own blood, thus securing an eternal redemption.'</p>",
    "6": "<p>A direct type: 'And the priest shall dip his finger in the blood and sprinkle part of the blood seven times before YHWH in front of the veil of the sanctuary.' Seven sprinklings before the veil — the veil that separated the holy place from the most holy. Seven = completeness; the blood of the sin offering is completely applied to the boundary between holy and most holy. At Christ's death, 'the curtain of the temple was torn in two, from top to bottom' (Matt 27:51) — the veil is not sprinkled but abolished. What the <em>chatat</em> blood reached toward, Christ's blood passed through entirely.</p>",
    "7": "<p>A shadow: 'And the priest shall put some of the blood on the horns of the altar of fragrant incense before YHWH that is in the tent of meeting, and all the rest of the blood of the bull he shall pour out at the base of the altar of burnt offering that is at the entrance of the tent of meeting.' Blood applied to both altars — the incense altar inside the tent and the burnt-offering altar outside. Christ's atonement reaches both: the inner sanctuary of prayer and the outer altar of sacrifice are both covered by his blood.</p>",
    "8": "<p>A shadow: 'And all the fat of the bull of the sin offering he shall remove from it, the fat covering the entrails and all the fat that is on the entrails.' The fat portions of the sin offering follow the same rule as the peace offering — given to YHWH. Even in the sin offering, the best is given to God: the sin-covering sacrifice does not merely manage sin but offers God what is richest.</p>",
    "9": "<p>A shadow: 'And the two kidneys with the fat that is on them at the loins, and the long lobe of the liver that he shall remove with the kidneys.' The inner organs — the seat of hidden life — given to God even in the sin offering. Christ's inner surrender to the Father in Gethsemane ('not my will, but yours, be done,' Luke 22:42) is the ultimate inner-organ offering: the will, the deepest kernel of the self, placed on the altar.</p>",
    "10": "<p>A shadow: 'Just as these are taken from the ox of the sacrifice of the peace offerings; and the priest shall burn them on the altar of burnt offering.' The sin offering's fat portions match the peace offering's — the same God who is reconciled in the peace offering receives the best in the sin offering. The atonement of sin and the establishment of peace are both given to the same God who owns all fat.</p>",
    "11": "<p>A direct type: 'But the skin of the bull and all its flesh, with its head, its legs, its entrails, and its dung — all the rest of the bull — he shall carry outside the camp to a clean place, to the ash heap, and shall burn it up on a fire of wood.' The sin offering bull is burned <em>outside the camp</em> — not on the altar, but at the ash heap. This is the key geographical type. Hebrews 13:11: 'For the bodies of those animals whose blood is brought into the holy places by the high priest as a sacrifice for sin are burned outside the camp.'</p>",
    "12": "<p>A direct type: 'He shall carry the bull outside the camp and burn it up. Where the ash heap is, there it shall be burned.' Hebrews 13:12–13 makes the explicit typological application: 'So Jesus also suffered outside the gate in order to sanctify the people through his own blood. Therefore let us go to him outside the camp and bear the reproach he endured.' The site of the sin offering's disposal — outside the gate, outside the camp, at the ash heap — is the exact type of the cross at Golgotha outside Jerusalem. The burning outside the camp tells Israel: atonement happens not inside the holy place but at the place of shame and disposal.</p>",
    "13": "<p>A direct type: 'If the whole congregation of Israel sins unintentionally and the thing is hidden from the eyes of the assembly, and they do any one of the things that by YHWH's commandments ought not to be done, and they realize their guilt...' The communal sin offering addresses the entire nation sinning as one. Christ's death is the communal atonement: 'it is better for you that one man should die for the people, not that the whole nation should perish' (John 11:50) — Caiaphas spoke better than he knew; the high priest's inadvertent prophecy echoes the communal chatat logic.</p>",
    "14": "<p>A shadow: 'When the sin which they have committed becomes known, the assembly shall offer a bull from the herd for a sin offering and bring it in front of the tent of meeting.' The communal sin offering requires the same grade of animal as the priestly sin offering — a bull. Corporate sin is as weighty as priestly sin. Christ's atonement bears the full weight of corporate human guilt: 'He is the propitiation for our sins, and not for ours only but also for the sins of the whole world' (1 John 2:2).</p>",
    "15": "<p>A direct type: 'The elders of the congregation shall lay their hands on the head of the bull before YHWH, and the bull shall be killed before YHWH.' The elders represent the entire congregation in hand-laying — the whole community's guilt is transferred via representative identification. Christ's death is represented by his disciples, apostles, and ultimately all who believe: 'all of us like sheep have gone astray... and YHWH laid on him the iniquity of us all' (Isa 53:6).</p>",
    "16": "<p>A direct type: 'Then the anointed priest shall bring some of the blood of the bull into the tent of meeting.' Repeated from v5 — the blood goes inside the tent, into the sanctuary. Whether for priestly sin (v5) or congregational sin (v16), the same act: blood brought inside. Christ's blood, by a single act, covers all categories: 'he entered once for all into the holy places... by means of his own blood, thus securing an eternal redemption' (Heb 9:12).</p>",
    "17": "<p>A direct type: 'And the priest shall dip his finger in the blood and sprinkle it seven times before YHWH in front of the veil.' The sevenfold blood-sprinkling before the veil is repeated for the communal sin offering (cf. v6 for the priestly sin offering). The repetition of the identical act emphasizes that the same barrier — the veil — separates God from humanity whether the sin is individual or communal. The veil torn at the crucifixion is not torn for one person but for all: 'the curtain of the temple was torn in two, from top to bottom' (Matt 27:51) — from God's side, removing the barrier for all.</p>",
    "18": "<p>A shadow: 'And he shall put some of the blood on the horns of the altar that is in the tent of meeting before YHWH, and the rest of the blood he shall pour out at the base of the altar of burnt offering at the entrance of the tent of meeting.' Identical to v7 — blood on both altars. The repetition of the blood-rite for each category of sin (priest, congregation, leader, individual) drills into Israel: atonement requires the same act regardless of who sins. Christ's sacrifice is unrepeatable because he covered all categories in one act: 'by a single offering he has perfected for all time those who are being sanctified' (Heb 10:14).</p>",
    "19": "<p>A shadow: 'And all its fat he shall take from it and burn on the altar.' The fat to God — even in the communal sin offering, what is best goes to YHWH. Atonement is not merely housekeeping; it involves giving God the best in the midst of addressing the worst.</p>",
    "20": "<p>A direct type: 'Thus shall he do with the bull. As he did with the bull of the sin offering, so shall he do with this. And the priest shall make atonement for them, and they shall be forgiven.' The result: <em>venislach lahem</em> — 'and they shall be forgiven.' The sin offering consistently produces forgiveness (vv20, 26, 31, 35). Forgiveness is not God's reluctant concession but the designed outcome of the sacrifice. In Christ, this forgiveness is total and permanent: 'as far as the east is from the west, so far does he remove our transgressions from us' (Ps 103:12); 'I will remember their sins no more' (Heb 10:17).</p>",
    "21": "<p>A direct type: 'And he shall carry the bull outside the camp and burn it up as he burned the first bull; it is the sin offering for the assembly.' The communal sin offering also burns outside the camp — the same as the priestly sin offering (v12). The repetition nails the outside-the-camp theme for the third time across Lev 4:11–12 and 4:21. By the time Hebrews 13:11–13 cites it, Israel has been prepared through repeated exposure to this spatial type: atonement happens outside the holy zone, at the place of shame.</p>",
    "22": "<p>A shadow: 'When a leader sins, doing unintentionally any one of all the things that by the commandments of YHWH his God ought not to be done, and realizes his guilt...' The <em>nasi</em> (leader/ruler) requires a sin offering for his own unintentional sin. Leaders are not exempt — they are subject to the same need for atonement. The religious leaders who condemned Jesus did so thinking they were serving God; the sin offering for a leader's unwitting sin covers exactly this scenario (Acts 3:17).</p>",
    "23": "<p>A shadow: 'Or the sin which he has committed is made known to him, he shall bring as his offering a goat, a male without defect.' The leader's offering steps down from a bull to a male goat — the graduated scale of sin offerings matches the social hierarchy: priest (bull), congregation (bull), leader (male goat), individual (female goat or lamb). The gradation does not mean some sins are more forgivable but that each station carries its corresponding weight of responsibility.</p>",
    "24": "<p>A direct type: 'And he shall lay his hand on the head of the goat and kill it in the place where they kill the burnt offering before YHWH; it is a sin offering.' Hand-laying for the leader — the same act as for every other level. The sin offering's identification-requirement applies regardless of rank. Christ, who had no rank below him, took the place of identification with the lowest: 'he humbled himself by becoming obedient to the point of death, even death on a cross' (Phil 2:8).</p>",
    "25": "<p>A shadow: 'Then the priest shall take some of the blood of the sin offering with his finger and put it on the horns of the altar of burnt offering and pour out the rest of its blood at the base of the altar of burnt offering.' The leader's sin offering blood stays at the outer altar — unlike the priestly and congregational sin offerings whose blood enters the tent. The spatial gradient of blood application (inside the veil, outer altar) maps the graduated access to God's presence. Christ's blood, brought into the heavenly sanctuary itself, provides the highest access for all.</p>",
    "26": "<p>A direct type: 'And all its fat he shall burn on the altar, like the fat of the sacrifice of peace offerings. So the priest shall make atonement for him for his sin, and he shall be forgiven.' <em>Venislach lo</em> — 'and he shall be forgiven.' The sin offering's result is always forgiveness — the leader is forgiven exactly as the priest (v20), as the congregation (v20), as the individual will be (vv31, 35). The forgiveness is identical regardless of level. Christ's 'once for all' (Heb 10:10) forgiveness is equally distributed: 'there is no distinction: for all have sinned... and are justified by his grace as a gift' (Rom 3:22–24).</p>",
    "27": "<p>A direct type: 'If anyone of the common people sins unintentionally in doing any one of the things that by YHWH's commandments ought not to be done, and realizes his guilt...' The system culminates with the individual — any member of the common people. The sin offering was not only for priests and rulers but for every Israelite. Christ's atonement is personal: 'The Son of God loved me and gave himself for me' (Gal 2:20). The individual in Lev 4:27 is the prototype of every believer for whom Christ died specifically.</p>",
    "28": "<p>A shadow: 'Or the sin that he has committed is made known to him, he shall bring for his offering a female goat without blemish [<em>temimah</em>], a female, for his sin which he has committed.' The individual sin offering is female — the lowest level in the graduated system. The consistent requirement of <em>temimah</em> (unblemished) at every level, including the least costly offering, maintains the principle: sinlessness in the substitute is non-negotiable regardless of economic level. No imperfect sacrifice can cover even one person's sin.</p>",
    "29": "<p>A direct type: 'And he shall lay his hand on the head of the sin offering and kill the sin offering in the place of burnt offering.' Hand-laying at the individual level — the last of four repetitions across chapter 4 (vv4, 15, 24, 29). The fourfold repetition across all social levels makes identification/substitution the unquestionable core of the entire sin offering system. Christ bore the hand-press of all humanity: 'He himself bore our sins in his body on the tree' (1 Pet 2:24).</p>",
    "30": "<p>A shadow: 'And the priest shall take some of its blood with his finger and put it on the horns of the altar of burnt offering and pour out all the rest of its blood at the base of the altar.' The individual's sin offering blood also remains at the outer altar — the same position as the leader's (v25). The spatial coding reflects that even the individual who cannot afford a bull receives the same effective atonement: 'For the Lord your God... is not partial and takes no bribe' (Deut 10:17).</p>",
    "31": "<p>A direct type: 'And all its fat he shall remove, as the fat is removed from the peace offerings, and the priest shall burn it on the altar for a pleasing aroma to YHWH. And the priest shall make atonement for him, and he shall be forgiven.' The third 'and he shall be forgiven' (<em>venislach lo</em>: vv20, 26, 31). The forgiveness formula is identical whether for a bull offered by the high priest or a female goat offered by the poorest Israelite. Christ's atonement produces the same forgiveness for all: 'in him we have redemption through his blood, the forgiveness of our trespasses, according to the riches of his grace' (Eph 1:7).</p>",
    "32": "<p>A shadow: 'If he brings a lamb as his offering for a sin offering, he shall bring a female without blemish.' The alternative individual sin offering — a female lamb instead of a female goat. The lamb option is the humblest form, requiring the same <em>temimah</em> (unblemished). This lamb-without-blemish, the individual's most basic provision, is the distant OT form of what John the Baptist sees: 'the Lamb of God, who takes away the sin of the world' (John 1:29).</p>",
    "33": "<p>A direct type: 'And he shall lay his hand on the head of the sin offering and kill it for a sin offering in the place where they kill the burnt offering.' Even the lamb requires hand-laying — the final occurrence in chapter 4 of this central act. The sequence (bull/bull/goat/goat/lamb) ends with the lamb, the smallest and humblest. The NT sin offering will be a lamb — 'the Lamb who was slain from the foundation of the world' (Rev 13:8).</p>",
    "34": "<p>A direct type: 'Then the priest shall take some of the blood of the sin offering with his finger and put it on the horns of the altar of burnt offering, and pour out all the rest of its blood at the base of the altar.' The blood of the individual's lamb is poured at the base of the altar — poured out, not just applied. Matthew 26:28: 'this is my blood of the covenant, which is poured out for many for the forgiveness of sins.' The lamb's blood poured at the altar base is the type of Christ's blood poured out at the cross.</p>",
    "35": "<p>A direct type: 'And all its fat he shall remove as the fat of the lamb is removed from the sacrifice of peace offerings, and the priest shall burn it on the altar, on top of YHWH's food offerings. And the priest shall make atonement for him for the sin which he has committed, and he shall be forgiven.' The fourth and final 'and he shall be forgiven' (<em>venislach lo</em>: vv20, 26, 31, 35) closes the sin offering chapter. The fourfold repetition (priest, congregation, leader, individual) covers every level of the community. Christ's one offering covers all four levels simultaneously and permanently: 'by a single offering he has perfected for all time those who are being sanctified' (Heb 10:14). The graduated Levitical system required a separate sacrifice for each level; Christ's sacrifice is the one act that achieves what the fourfold system only approximated.</p>"
  }
}

def main():
    c = load_comm('mkt-christ', 'leviticus')
    merge_comm(c, CHRIST)
    save_comm('mkt-christ', 'leviticus', c)
    print('Leviticus 1-4 mkt-christ written.')

if __name__ == '__main__':
    main()
